export type ValueOf<T> = T[keyof T];
export type KeyOf<T> = keyof T;

export type AddProperty<T, Key extends string, Value> = T & {
  [K in Key]: Value;
};
export type AddPropertyToInterfaceValues<
  Interface,
  Key extends string,
  Value,
> = {
  [_ in keyof Interface]: AddProperty<Interface[_], Key, Value>;
};
export type AddKeysAsPropertyToInterface<Interface, Key extends string> = {
  [Value in keyof Interface]: AddProperty<Interface[Value], Key, Value>;
};

export type ExtendInterfaceValues<Interface, T> = {
  [Key in keyof Interface]: [Interface[Key]] extends [undefined]
    ? T
    : Interface[Key] & T;
};

export type CapitalizeFirstLetter<S extends string> =
  S extends `${infer First}${infer Rest}` ? `${Uppercase<First>}${Rest}` : S;
export type AddPrefix<
  P extends string,
  S extends string,
> = `${P}${CapitalizeFirstLetter<S>}`;
export type AddPrefixToInterfaceKeys<Interface, P extends string> = {
  [Key in keyof Interface as `${AddPrefix<P, Key & string>}`]: Interface[Key];
};

export type IfAny<T, Y, N> = 0 extends 1 & T ? Y : N;

export type OneOrMany<T> = T | T[];

export function Singleton<T extends abstract new (...args: any[]) => any>(
  target: T,
  context: ClassDecoratorContext,
) {
  let shared: InstanceType<T> | undefined;

  return class extends target {
    static get shared() {
      return (shared ??= new this());
    }

    constructor(...args: any[]) {
      if (shared) {
        throw new Error(
          `${target.name} is a singleton - use ${target.name}.shared`,
        );
      }

      super(...args);

      shared = this;
    }
  } as T & {
    readonly shared: InstanceType<T>;
  };
}
