export function getInterpolation(
  value: number,
  min: number,
  max: number,
  span: number,
) {
  if (span == undefined) {
    span = max - min;
  }
  return (value - min) / span;
}

export const Uint16Max = 2 ** 16;
export const Int16Max = 2 ** 15;
export const Int16Min = -(2 ** 15) - 1;

function removeLower2Bytes(number: number) {
  const lower2Bytes = number % Uint16Max;
  return number - lower2Bytes;
}

const timestampThreshold = 60_000;

export function parseTimestamp(
  dataView: DataView<ArrayBuffer>,
  byteOffset: number,
) {
  const now = Date.now();
  const nowWithoutLower2Bytes = removeLower2Bytes(now);
  const lower2Bytes = dataView.getUint16(byteOffset, true);
  let timestamp = nowWithoutLower2Bytes + lower2Bytes;
  const timestampDifference = Math.abs(now - timestamp);
  if (timestampDifference > timestampThreshold) {
    _console.log("correcting timestamp delta");
    timestamp += Uint16Max * Math.sign(now - timestamp);
  }
  _console.log({
    now,
    nowWithoutLower2Bytes,
    lower2Bytes,
    timestamp,
    timestampDifference,
  });
  return timestamp;
}

export interface Vector2 {
  x: number;
  y: number;
}

export function getVector2Length(vector: Vector2) {
  const { x, y } = vector;
  return Math.sqrt(x ** 2 + y ** 2);
}

export function getVector2Distance(a: Vector2, b: Vector2) {
  return Math.sqrt((b.x - a.x) ** 2 + (b.y - a.y) ** 2);
}

export function getVector2DistanceSquared(a: Vector2, b: Vector2) {
  return (b.x - a.x) ** 2 + (b.y - a.y) ** 2;
}

export function getVector2Angle(vector: Vector2) {
  const { x, y } = vector;
  return Math.atan2(y, x);
}

export function getVector2Midpoint(a: Vector2, b: Vector2): Vector2 {
  return {
    x: (a.x + b.x) / 2,
    y: (a.y + b.y) / 2,
  };
}

export function multiplyVector2ByScalar(
  vector: Vector2,
  scalar: number,
): Vector2 {
  let { x, y } = vector;
  x *= scalar;
  y *= scalar;
  return { x, y };
}
export function normalizedVector2(vector: Vector2): Vector2 {
  return multiplyVector2ByScalar(vector, 1 / getVector2Length(vector));
}

export interface Vector3 extends Vector2 {
  z: number;
}

export interface Quaternion {
  x: number;
  y: number;
  z: number;
  w: number;
}

export interface Euler {
  heading: number;
  pitch: number;
  roll: number;
  absolute?: boolean;
}
export const defaultEuler: Euler = {
  heading: 0,
  pitch: 0,
  roll: 0,
  absolute: false,
};

export function getVector3Length(vector: Vector3) {
  const { x, y, z } = vector;
  return Math.sqrt(x ** 2 + y ** 2 + z ** 2);
}

export function clamp(value: number, min: number = 0, max: number = 1) {
  return Math.min(Math.max(value, min), max);
}

export function degToRad(deg: number) {
  return deg * (Math.PI / 180);
}

export function radToDeg(rad: number) {
  return rad * (180 / Math.PI);
}

export const twoPi = Math.PI * 2;
export function normalizeRadians(rad: number): number {
  return ((rad % twoPi) + twoPi) % twoPi;
}

export function pointInPolygon(pt: Vector2, polygon: Vector2[]): boolean {
  let inside = false;
  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
    const xi = polygon[i].x,
      yi = polygon[i].y;
    const xj = polygon[j].x,
      yj = polygon[j].y;

    const intersect =
      yi > pt.y !== yj > pt.y &&
      pt.x < ((xj - xi) * (pt.y - yi)) / (yj - yi) + xi;
    if (intersect) inside = !inside;
  }
  return inside;
}

// https://github.com/mrdoob/three.js/blob/master/src/math/Euler.js#L270
export function quaternionToEulerYXZ(q: Quaternion): Euler {
  const { x, y, z, w } = q;

  const m11 = 1 - 2 * (y * y + z * z);
  const m13 = 2 * (x * z + y * w);

  const m21 = 2 * (x * y + z * w);
  const m22 = 1 - 2 * (x * x + z * z);
  const m23 = 2 * (y * z - x * w);

  const m31 = 2 * (x * z - y * w);
  const m33 = 1 - 2 * (x * x + y * y);

  const eulerX = Math.asin(-clamp(m23, -1, 1));

  let eulerY: number;
  let eulerZ: number;

  if (Math.abs(m23) < 0.9999999) {
    eulerY = Math.atan2(m13, m33);
    eulerZ = Math.atan2(m21, m22);
  } else {
    eulerY = Math.atan2(-m31, m11);
    eulerZ = 0;
  }

  return {
    pitch: eulerX,
    heading: eulerY,
    roll: eulerZ,
  };
}
